SELECT count(*) FROM movie_info, title, info_type, cast_info, role_type, char_name, name, aka_name, movie_keyword WHERE movie_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_keyword.movie_id = title.id;